using Microsoft.AspNetCore.Mvc;
using System.Net.Http;
using System.Threading.Tasks;

[ApiController]
[Route("api/[controller]")]
public class WebhookProxyController : ControllerBase
{
    private readonly HttpClient _httpClient;

    public WebhookProxyController(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [HttpPost("{*path}")]
    public async Task<IActionResult> Proxy(string path)
    {
        if (!Request.Headers.TryGetValue("X-Forwarded-Host", out var forwardedHost))
        {
            return BadRequest("Missing X-Forwarded-Host header");
        }

        var targetUrl = $"{forwardedHost}/{path}";
        
        try
        {
            var requestContent = Request.ContentLength > 0 
                ? new StreamContent(Request.Body) 
                : null;

            var httpRequest = new HttpRequestMessage
            {
                Method = new HttpMethod(Request.Method),
                RequestUri = new Uri(targetUrl),
                Content = requestContent
            };

            foreach (var header in Request.Headers)
            {
                if (!httpRequest.Headers.TryAddWithoutValidation(header.Key, header.Value.ToArray()))
                {
                    httpRequest.Content?.Headers.TryAddWithoutValidation(header.Key, header.Value.ToArray());
                }
            }

            var response = await _httpClient.SendAsync(httpRequest);
            
            var responseContent = await response.Content.ReadAsByteArrayAsync();
            
            return new ContentResult
            {
                Content = System.Text.Encoding.UTF8.GetString(responseContent),
                StatusCode = (int)response.StatusCode,
                ContentType = response.Content.Headers.ContentType?.ToString()
            };
        }
        catch (Exception ex)
        {
            return StatusCode(500, ex.Message);
        }
    }
